INSERT INTO `wp_options` VALUES ('299','gitts_hero_titulo','Grupo de Investigación en Tecnologías Avanzadas de Telecomunicación y Procesamiento de Señales','auto');
INSERT INTO `wp_options` VALUES ('300','gitts_hero_subtitulo','Investigación de frontera que conecta señales y datos con soluciones de impacto.','auto');
INSERT INTO `wp_options` VALUES ('301','gitts_mision','Generar, validar y transferir conocimiento mediante investigación científica y desarrollo tecnológico en telecomunicaciones, procesamiento de señales y áreas afines (sensado electromagnético, instrumentación, electrónica, radiofrecuencia y óptica). Con un enfoque científico riguroso y prototipos experimentales, GITTS transforma señales y datos en soluciones confiables, eficientes y seguras, formando talento e impulsando la innovación para atender retos relevantes en la industria, el sector público y la sociedad de manera sostenible.','auto');
INSERT INTO `wp_options` VALUES ('302','gitts_vision','Ser un grupo de investigación de referencia en Panamá y la región, reconocido por la solidez de su trabajo científico-tecnológico y la pertinencia de sus líneas de investigación, así como por la calidad de su formación y su capacidad para liderar proyectos aplicados. GITTS aspira a consolidarse como un espacio de innovación y colaboración internacional, con impacto sostenido en el desarrollo científico, productivo y social, actuando como puente entre la academia y la industria.','auto');
INSERT INTO `wp_options` VALUES ('303','gitts_telefono','(+507) 560-3061','auto');
INSERT INTO `wp_options` VALUES ('304','gitts_email_contacto','gitts@utp.ac.pa','auto');
INSERT INTO `wp_options` VALUES ('305','gitts_direccion','Edificio de Investigación e Innovación (ELII), Piso 2','auto');
INSERT INTO `wp_options` VALUES ('306','gitts_campus','Campus Víctor Levi Sasso, Universidad Tecnológica de Panamá, Ciudad de Panamá','auto');
INSERT INTO `wp_options` VALUES ('307','gitts_intro_miembros','GITTS está conformado por un equipo multidisciplinario de investigadores, estudiantes y colaboradores que comparten una visión común: impulsar el conocimiento y la innovación en telecomunicaciones y procesamiento de señales.','auto');
INSERT INTO `wp_options` VALUES ('308','gitts_intro_produccion','La investigación desarrollada en GITTS se traduce en generación de conocimiento, formación de nuevos investigadores y desarrollo de tecnologías con impacto.','auto');
INSERT INTO `wp_options` VALUES ('309','gitts_intro_investigacion','Nuestro trabajo integra teoría, experimentación y desarrollo tecnológico para crear soluciones innovadoras con impacto en sectores como energía, salud, agricultura, medio ambiente e infraestructura digital.','auto');
INSERT INTO `wp_options` VALUES ('310','gitts_intro_infraestructura','Conoce las instalaciones y capacidades que sustentan nuestra investigación y desarrollo tecnológico.','auto');
INSERT INTO `wp_options` VALUES ('311','gitts_intro_quienes','El Grupo de Investigación en Tecnologías Avanzadas de Telecomunicación y Procesamiento de Señales (GITTS) surge como una iniciativa estratégica para fortalecer las capacidades de investigación, innovación y formación de talento en áreas fundamentales para la ingeniería contemporánea.','auto');
INSERT INTO `wp_options` VALUES ('312','gitts_intro_unete','GITTS es un espacio abierto a la colaboración, el aprendizaje y la innovación. Invitamos a estudiantes, investigadores, instituciones y empresas a participar en nuestras actividades de investigación y desarrollo en telecomunicaciones, procesamiento de señales y tecnologías afines.','auto');
INSERT INTO `wp_options` VALUES ('339','_site_transient_timeout_php_check_17abe05a01db95b436b41c019f2a8755','1775249193','off');
INSERT INTO `wp_options` VALUES ('340','_site_transient_php_check_17abe05a01db95b436b41c019f2a8755','a:5:{s:19:\"recommended_version\";s:3:\"8.3\";s:15:\"minimum_version\";s:6:\"7.2.24\";s:12:\"is_supported\";b:1;s:9:\"is_secure\";b:1;s:13:\"is_acceptable\";b:1;}','off');
INSERT INTO `wp_options` VALUES ('348','gitts_sobre_gitts','<p>El <strong>Grupo de Investigación en Tecnologías Avanzadas de Telecomunicación y Procesamiento de Señales (GITTS)</strong> surge como una iniciativa estratégica para fortalecer las capacidades de investigación, innovación y formación de talento en áreas fundamentales para la ingeniería contemporánea.</p><p>El grupo articula de manera sostenida el trabajo científico en telecomunicaciones, procesamiento de señales, electrónica, sistemas de radiofrecuencia, sistemas ópticos, instrumentación y campos afines, integrando capacidades experimentales, analíticas y de diseño orientadas a la generación de conocimiento y al desarrollo de soluciones tecnológicas.</p><p>Las telecomunicaciones y el procesamiento de señales constituyen hoy pilares esenciales del desarrollo económico y social. La conectividad segura y eficiente es un habilitador clave para sectores como la salud, la educación, la industria, la energía y el medio ambiente. En este contexto, fortalecer capacidades científicas y tecnológicas a nivel local resulta fundamental para diseñar, evaluar e implementar sistemas de comunicación modernos.</p><p>A través de la investigación, la formación de estudiantes, la producción científica y el desarrollo de tecnologías, GITTS contribuye a consolidar una comunidad académica dinámica, fortalecer la colaboración con actores nacionales e internacionales y generar soluciones innovadoras con impacto en la sociedad.</p><p>De esta manera, el grupo aporta al fortalecimiento de la capacidad científica y tecnológica de la Universidad y del país, promoviendo el desarrollo sostenible y la formación de profesionales altamente calificados.</p>','auto');
INSERT INTO `wp_options` VALUES ('349','gitts_valores_fund_data','[{\"titulo\":\"Integridad y ética científica\",\"descripcion\":\"Honestidad, responsabilidad y transparencia en cada etapa de la investigación.\"},{\"titulo\":\"Rigor y excelencia\",\"descripcion\":\"Calidad metodológica, validación experimental y mejora continua.\"},{\"titulo\":\"Creatividad e innovación\",\"descripcion\":\"Ideas novedosas con disciplina para convertirlas en tecnología útil.\"},{\"titulo\":\"Colaboración y trabajo en equipo\",\"descripcion\":\"Proyectos interdisciplinarios que aprovechan fortalezas diversas.\"},{\"titulo\":\"Diversidad e inclusión\",\"descripcion\":\"Entorno diverso como fuente de creatividad y mejores soluciones.\"},{\"titulo\":\"Compromiso con la sociedad\",\"descripcion\":\"Difusión de resultados y transferencia responsable de tecnologías.\"},{\"titulo\":\"Sostenibilidad\",\"descripcion\":\"Eficiencia energética, impacto ambiental y social positivos.\"}]','auto');
INSERT INTO `wp_options` VALUES ('350','gitts_objetivos_data','[{\"titulo\":\"Investigación de frontera\",\"descripcion\":\"Impulsar investigación en telecomunicaciones, procesamiento de señales, IA aplicada y tecnologías emergentes, con producción científica en revistas y conferencias internacionales.\"},{\"titulo\":\"Desarrollo tecnológico\",\"descripcion\":\"Desarrollar metodologías, prototipos e instrumentos para medición, adquisición, transmisión y análisis de señales y datos.\"},{\"titulo\":\"Formación de talento\",\"descripcion\":\"Formar talento humano de alto nivel, integrando estudiantes de pregrado y posgrado en proyectos de investigación.\"},{\"titulo\":\"Redes de colaboración\",\"descripcion\":\"Fortalecer redes nacionales e internacionales con universidades, centros de investigación, industria y sector público.\"},{\"titulo\":\"Transferencia a la sociedad\",\"descripcion\":\"Transferir conocimiento y tecnología mediante servicios especializados, consultoría y difusión científica.\"}]','auto');
INSERT INTO `wp_options` VALUES ('353','gitts_especializacion_data','[{\"titulo\":\"Óptica y Fotónica\"},{\"titulo\":\"Procesamiento de Señales\"},{\"titulo\":\"Inteligencia Artificial\"},{\"titulo\":\"Sensado Remoto\"},{\"titulo\":\"Sistemas de Microondas\"},{\"titulo\":\"Telecomunicaciones\"},{\"titulo\":\"IoT\"},{\"titulo\":\"Imágenes Hiperespectrales\"},{\"titulo\":\"Machine Learning\"},{\"titulo\":\"Sensado Compresivo\"},{\"titulo\":\"Radiocomunicaciones\"},{\"titulo\":\"Agricultura de Precisión\"},{\"titulo\":\"Deep Learning\"},{\"titulo\":\"NLP\"}]','auto');
