INSERT INTO `wp_postmeta` VALUES ('634','145','pub_resumen','Diseño e implementación de un prototipo de sistema de comunicación óptica por luz visible (VLC) para transmisión de datos en entornos interiores, evaluando tasas de transmisión, distancia efectiva y robustez frente a interferencias lumínicas ambientales.');
INSERT INTO `wp_postmeta` VALUES ('635','146','pub_resumen','Desarrollo de una red de sensores inalámbricos de bajo consumo para la recolección y transmisión de variables ambientales (temperatura, humedad, calidad del aire) en tiempo real, con visualización en plataforma web.');
INSERT INTO `wp_postmeta` VALUES ('636','147','pub_resumen','Estudio comparativo de estándares de televisión digital terrestre (ISDB-T, DVB-T2, ATSC) aplicables a Panamá, con análisis de cobertura, calidad de señal y requerimientos de infraestructura para la transición analógica-digital.');
INSERT INTO `wp_postmeta` VALUES ('637','148','pub_resumen','Modelado, simulación y análisis de desempeño de códigos LDPC (Low-Density Parity-Check) en canales con desvanecimiento, evaluando tasas de error de bit y comparando con códigos turbo convencionales.');
INSERT INTO `wp_postmeta` VALUES ('638','149','pub_resumen','Implementación de algoritmos de reconstrucción de señales dispersas mediante técnicas de sensado compresivo, con aplicación a señales de radar y validación experimental en laboratorio.');
INSERT INTO `wp_postmeta` VALUES ('639','150','pub_resumen','Diseño y construcción de un vehículo radio-controlado con sistema de comunicación inalámbrica, incluyendo telemetría de sensores y control remoto vía protocolo ZigBee.');
INSERT INTO `wp_postmeta` VALUES ('640','151','pub_resumen','Sistema de visión por computadora para reconocimiento de gestos de mano en tiempo real, utilizando técnicas de segmentación de color y descriptores de forma para interfaz hombre-máquina.');
INSERT INTO `wp_postmeta` VALUES ('641','152','pub_resumen','Desarrollo de un simulador didáctico de sistemas de espectro ensanchado por secuencia directa (DSSS-CDMA), con interfaz gráfica para visualización de señales, códigos de ensanchamiento y análisis de interferencia multiusuario.');
